#!/usr/bin/env Rscript

# =============================================================================
# PESTFLY — Step 4: Hierarchical SNP-based origin assignment
# =============================================================================
#
# Purpose
# -------
# Assign query/intercept samples using the diagnostic SNP panels generated by
# Step 3.
#
# Assignment hierarchy:
#
#   1. P1 macroregion assignment:
#        Africa vs Asia
#
#   2. Conditional subregion assignment:
#        if P1 == Africa with High/Moderate confidence -> P2 Africa subregions
#        if P1 == Asia   with High/Moderate confidence -> P3 Asia subregions
#
# P4 population-level assignment is not used in the default workflow.
#
# =============================================================================
# Conceptual model
# =============================================================================
#
# Step 3 ranks SNPs by informativeness for each panel. Step 4 tests whether each
# query assignment is stable across increasing Top-K SNP subsets.
#
# Here, K means:
#
#   "Use the top K ranked SNPs from the panel."
#
# It does NOT mean:
#
#   - number of populations;
#   - ADMIXTURE K;
#   - k-means clustering.
#
# Example K grid:
#
#   1, 2, 3, 4, 5, 10, 20, 50, 100, 200, 500,
#   1000, 2000, 5000, 10000, all available SNPs
#
# The small K values are kept in the raw output because they are diagnostically
# useful. They show whether assignments are already obvious from a few SNPs or
# whether the signal only becomes stable once more markers are included.
#
# However, small K values should not determine whether an assignment is reliable
# if they are below the minimum number of usable SNPs required for assignment.
#
# Therefore:
#
#   - all K values are written to the raw output;
#   - only usable K values enter stability calculations.
#
# A usable K value is one for which the query has at least:
#
#   - min_snps_query_macroregion non-missing SNPs for P1;
#   - min_snps_query_subregion   non-missing SNPs for P2/P3.
#
# By default:
#
#   P1 requires >= 200 usable SNPs
#   P2/P3 require >= 300 usable SNPs
#
# =============================================================================
# Improved reliability/stability logic
# =============================================================================
#
# A final call is accepted as High/Moderate only if all conditions are met:
#
#   1. the largest usable K gives enough posterior support;
#   2. the posterior gap between first and second class is large enough;
#   3. enough usable K values are available;
#   4. most usable K values agree with the final largest-K call;
#   5. the largest-K tail agrees with the final largest-K call.
#
# The key stability metrics are:
#
#   agreement_frac
#     proportion of all usable K values matching the final largest-K call.
#
#   tail_agreement_frac
#     proportion of the largest usable K values matching the final largest-K call.
#
# By default:
#
#   min_agreement      = 0.90
#   tail_fraction      = 0.50
#   min_tail_agreement = 1.00
#
# Meaning:
#
#   - at least 90% of usable K values must agree with the final call;
#   - the largest 50% of usable K values must agree completely with the final call.
#
# This allows noisy behaviour at very small K, while requiring convergence at
# larger SNP subsets.
#
# =============================================================================
# Main inputs
# =============================================================================
#
#   results/01_qc/metadata_clean.tsv
#   results/02_snp_panels/panels_index.tsv
#   results/02_snp_panels/panels/<panel_id>/snp_map.tsv
#   results/02_snp_panels/panels/<panel_id>/snp_matrix.rds
#
# =============================================================================
# Main outputs
# =============================================================================
#
#   results/04_origin_assignment/final_assignment.tsv
#   results/04_origin_assignment/final_assignment.rds
#   results/04_origin_assignment/step4_assignment_multilevel_macroregion_first.xlsx
#
#   results/04_origin_assignment/step4_K_grid_used.tsv
#   results/04_origin_assignment/step4_K_grid_used.rds
#
#   results/04_origin_assignment/P1_macroregion_raw.tsv / .rds
#   results/04_origin_assignment/P1_macroregion_stability.tsv / .rds
#   results/04_origin_assignment/P2_africa_subregion_raw.tsv / .rds
#   results/04_origin_assignment/P2_africa_subregion_stability.tsv / .rds
#   results/04_origin_assignment/P3_asia_subregion_raw.tsv / .rds
#   results/04_origin_assignment/P3_asia_subregion_stability.tsv / .rds
#
# =============================================================================
# Recommended run
# =============================================================================
#
#   Rscript steps/step4_multilevel_assignment/run.R
#
# Explicit extended-K run:
#
#   Rscript steps/step4_multilevel_assignment/run.R \
#     --extra_K 1000,2000,5000,10000 \
#     --include_all_snps_K TRUE \
#     --tail_fraction 0.50 \
#     --min_tail_agreement 1.00 \
#     --min_agreement 0.90
#
# =============================================================================

suppressPackageStartupMessages({
  library(optparse)
  library(data.table)
  library(openxlsx)
})

# =============================================================================
# Repo-root detection
# =============================================================================

find_repo_root <- function(max_up = 10L) {
  wd <- normalizePath(getwd(), winslash = "/", mustWork = TRUE)
  cand <- wd
  
  for (i in seq_len(max_up + 1L)) {
    if (dir.exists(file.path(cand, "data")) && dir.exists(file.path(cand, "steps"))) {
      return(cand)
    }
    
    parent <- normalizePath(file.path(cand, ".."), winslash = "/", mustWork = FALSE)
    if (identical(parent, cand)) break
    cand <- parent
  }
  
  wd
}

repo_root <- find_repo_root()

is_abs_path <- function(p) {
  grepl("^(?:[A-Za-z]:[/\\\\]|/)", p)
}

resolve_path <- function(p, root = repo_root) {
  if (is.null(p) || !nzchar(p)) return(p)
  if (is_abs_path(p)) return(normalizePath(p, winslash = "/", mustWork = FALSE))
  normalizePath(file.path(root, p), winslash = "/", mustWork = FALSE)
}

