fix_panel_dir <- function(d) {
  if (is.na(d)) return(d)
  if (dir.exists(d)) return(d)
  
  d2 <- file.path(opt$step3_dir, d)
  if (dir.exists(d2)) return(d2)
  
  d3 <- file.path(opt$step3_dir, "panels", basename(d))
  if (dir.exists(d3)) return(d3)
  
  d
}

