make_sub_call <- function(stab, panel_label) {
  if (is.null(stab) || nrow(stab) == 0L || !("sample_id" %in% names(stab))) {
    return(data.table(
      sample_id = character(),
      subregion_call = character(),
      subregion_confidence = character(),
      subregion_reason = character(),
      subregion_panel = character(),
      subregion_maxK_used = numeric(),
      subregion_maxK_post = numeric(),
      subregion_maxK_gap = numeric(),
      subregion_agreement = numeric(),
      subregion_tail_agreement = numeric(),
      subregion_tail_fraction = numeric(),
      subregion_stable_from_K = numeric(),
      subregion_nK = integer(),
      subregion_nK_total_tested = integer(),
      subregion_nK_usable_for_stability = integer(),
      subregion_maxK_nsnps = integer()
    ))
  }
  
  stab[
    ,
    {
      fc <- final_call(
        .SD,
        high_thr = opt$high_posterior,
        mod_thr = opt$moderate_posterior,
        min_gap = opt$min_gap_subregion,
        min_agreement = opt$min_agreement,
        min_K = opt$min_K_available,
        min_tail_agreement = opt$min_tail_agreement
      )
      
      data.table(
        subregion_call = fc$call,
        subregion_confidence = fc$label,
        subregion_reason = fc$reason,
        subregion_panel = panel_label,
        subregion_maxK_used = maxK_used,
        subregion_maxK_post = maxK_top_posterior,
        subregion_maxK_gap = maxK_gap,
        subregion_agreement = agreement_frac,
        subregion_tail_agreement = tail_agreement_frac,
        subregion_tail_fraction = tail_fraction,
        subregion_stable_from_K = stable_from_K,
        subregion_nK = n_K_available,
        subregion_nK_total_tested = n_K_total_tested,
        subregion_nK_usable_for_stability = n_K_usable_for_stability,
        subregion_maxK_nsnps = maxK_n_snps_used
      )
    },
    by = sample_id
  ]
}

